mapper.select:
SELECT count(*) total FROM ( SELECT DISTINCT province_id, province_name FROM region_city_local) a, ( SELECT a.*, b.user_name FROM tfp_maintain_team_info a LEFT JOIN tau_user b ON a.OWNER_ID=b.user_id) b LEFT JOIN tau_user c ON b.MODIFY_USER_ID=c.user_id WHERE a.province_id=b.province_id
and b.professional_id=${professionalType}
and b.PROVINCE_ID=${provinceId}
and b.MTEAM_ID=${mteamId}
and b.MTEAM_NAME=${mteamName}

SELECT concat(b.PROVINCE_ID,':',b.MTEAM_ID) as row_key, b.MTEAM_ID, b.PROVINCE_ID, b.PROFESSIONAL_ID, b.professional_name, a.province_name, b.MTEAM_NAME, b.DIMENSIONS, b.ALARMS_FIELDS_COND, b.user_name creator, b.CREATE_TIME, c.user_name modifier, b.LATEST_TIME, b.RELATED_RULE_ID FROM ( SELECT DISTINCT province_id, province_name FROM region_city_local) a, ( SELECT a.*, b.user_name FROM tfp_maintain_team_info a LEFT JOIN tau_user b ON a.OWNER_ID=b.user_id) b LEFT JOIN tau_user c ON b.MODIFY_USER_ID=c.user_id WHERE a.province_id=b.province_id
and b.professional_id=${professionalType} and b.PROVINCE_ID=${provinceId}
order by LATEST_TIME , CREATE_TIME desc
limit ${startNum}, ${endNum}


SELECT a.user_id, a.zh_name,a.mobilephone,a.email,b.dept_id,b.dept_name FROM tai_userinfo a,tai_deptinfo b WHERE a.dept_id=b.dept_id



	and b.province_id= ${provinceId}




	and b.region_id= ${regionId}


	    select * from tai_deptinfo 
        where 1=1



            and province_id= ${provinceId}




			and region_id= ${regionId}


SELECT DISTINCT region_id,province_id,province_name,region_name FROM region_city_local
where 1=1



	and province_id= ${provinceId}




	and region_id= ${regionId}


select distinct mteam_id,mteam_name,professional_id,professional_name ,province_id,related_rule_id from tfp_maintain_team_info
where 1=1



	and province_id= ${provinceId}


SELECT count(*) total FROM tfa_alarmresourcebyeoms
where 1=1



	and province_id= ${provinceId}




	and region_id= ${regionId}




	and date_time= "${dateTime}"




	and rule_type= "${ruleType}"




	and professional_type= ${professionalType}




	AND  DATE_TIME=DATE_SUB(CURDATE(),INTERVAL 0 DAY)

select province_id,unique_rdn,date_time,professional_type,rule_type,object_class,ems_name,ne_label, int_id,region_name,region_id,city_name,city_id,machine_room,site_no,insert_db_time,operate_user, accept_id,accept_name,accept_dept_id,accept_dept_name,accept_tel,accept_night_id,accept_night_name,accept_night_dept_id,accept_night_dept_name,accept_night_tel, agent_id,agent_name,agent_dept_id,agent_dept_name,agent_tel,copy_id,copy_name,copy_dept_id,copy_dept_name,copy_tel, sms_id,sms_name,sms_dept_id,sms_dept_name,sms_tel,child_id,child_name,child_dept_id,child_dept_name,child_tel, audit_id,audit_name,audit_dept_id,audit_dept_name,audit_tel from tfa_alarmresourcebyeoms where 1=1
and province_id= ${provinceId}
and region_id= ${regionId}
and date_time= "${dateTime}"
and rule_type= "${ruleType}"
and professional_type= ${professionalType}
AND DATE_TIME=DATE_SUB(CURDATE(),INTERVAL 0 DAY)
order by date_time DESC limit ${startNum}, ${endNum}

SELECT b.txt professional_type,a.province_id,a.unique_rdn,a.date_time,a.professional_type,a.rule_type,a.object_class,a.ems_name,a.ne_label, a.int_id,a.region_name,a.region_id,a.city_name,a.city_id,a.machine_room,a.site_no,a.insert_db_time,a.operate_user, a.accept_id,a.accept_name,a.accept_dept_id,a.accept_dept_name,a.accept_tel,a.accept_night_id,a.accept_night_name,a.accept_night_dept_id,a.accept_night_dept_name,a.accept_night_tel, a.agent_id,a.agent_name,a.agent_dept_id,a.agent_dept_name,a.agent_tel,a.copy_id,a.copy_name,a.copy_dept_id,a.copy_dept_name,copy_tel, a.sms_id,a.sms_name,a.sms_dept_id,a.sms_dept_name,a.sms_tel,a.child_id,a.child_name,a.child_dept_id,a.child_dept_name,a.child_tel, a.audit_id,a.audit_name,a.audit_dept_id,a.audit_dept_name,a.audit_tel FROM TFA_ALARMRESOURCEBYEOMS a,(SELECT id,txt FROM tia_alarm_dict WHERE TYPE=1001) b WHERE a.professional_type=b.id AND a.DATE_TIME=DATE_SUB(CURDATE(),INTERVAL 0 DAY) AND ((b.txt LIKE '%${selectVal}%') OR (a.region_name LIKE '%${selectVal}%') OR (a.rule_type LIKE '%${selectVal}%') OR (a.ne_label LIKE '%${selectVal}%') OR (a.accept_name LIKE '%${selectVal}%') OR (a.accept_night_name LIKE '%${selectVal}%') OR (a.agent_name LIKE '%${selectVal}%') OR (a.copy_name LIKE '%${selectVal}%') OR (a.sms_name LIKE '%${selectVal}%') OR (a.child_name LIKE '%${selectVal}%') OR (a.audit_name LIKE '%${selectVal}%'))
and a.professional_type= '${professionalType}'
and a.province_id= ${provinceId}
and a.region_id= ${regionId}
limit ${startNum}, ${endNum}

 SELECT count(*) total FROM TFA_ALARMRESOURCEBYEOMS a,(SELECT id,txt FROM tia_alarm_dict WHERE TYPE=1001) b WHERE a.professional_type=b.id  AND ((b.txt LIKE '%${selectVal}%') OR (a.region_name LIKE '%${selectVal}%') OR (a.rule_type LIKE '%${selectVal}%') OR (a.ne_label LIKE '%${selectVal}%') OR (a.accept_name LIKE '%${selectVal}%') OR (a.accept_night_name LIKE '%${selectVal}%') OR (a.agent_name LIKE '%${selectVal}%') OR (a.copy_name LIKE '%${selectVal}%') OR (a.sms_name LIKE '%${selectVal}%') OR (a.child_name LIKE '%${selectVal}%') OR (a.audit_name LIKE '%${selectVal}%')) 


